export const 雷神散形 = (bi) => {
    const u = bi.u;
    const 線 = (書, 寬 = 0.55) => bi.一筆({ 寬: 寬 * u, 起: '藏', 收: '出' }, 書);
    // 獸首（雙白目，吻左張）
    bi.塊(t => t.M(-1.8, 3.4)
        .C(-0.6, 2.8, 1.0, 2.6, 2.4, 2.9) // 頂
        .C(3.4, 3.1, 4.2, 3.6, 4.4, 4.3) // 後腦
        .C(4.5, 5.0, 4.0, 5.6, 3.0, 5.9) // 後頷
        .C(1.6, 6.3, 0.0, 6.3, -1.2, 6.0) // 下緣
        .L(-3.8, 5.8).L(-2.1, 5.0).L(-3.9, 4.2) // 張吻雙尖（深）
        .C(-2.8, 3.9, -2.3, 3.6, -1.8, 3.4)
        .close());
    bi.鑿(t => {
        const k = 0.5523;
        for (const [x, z, r] of [[0.2, 4.2, 0.42], [1.8, 4.1, 0.42]]) {
            t.M(x + r, z).C(x + r, z + k * r, x + k * r, z + r, x, z + r)
                .C(x - k * r, z + r, x - r, z + k * r, x - r, z)
                .C(x - r, z - k * r, x - k * r, z - r, x, z - r)
                .C(x + k * r, z - r, x + r, z - k * r, x + r, z).close();
        }
    });
    // 粗鉤（雷霆律令——重筆ㄣ形＋引點）
    bi.dot(-7.0, 8.4, 0.55);
    線(p => p.M(-6.2, 8.2)
        .C(-5.2, 8.4, -4.4, 8.7, -4.0, 9.2)
        .C(-3.7, 9.8, -4.1, 10.4, -4.9, 10.6)
        .C(-5.6, 10.8, -6.2, 10.6, -6.5, 10.2), 1.15);
    線(p => p.M(-6.8, 11.4)
        .C(-6.0, 11.8, -5.2, 11.8, -4.5, 11.4), 0.7);
    // 蛇疊帶（雷火奔發／霹靂隨身——密摺四疊，圓端）
    線(p => p.M(-0.8, 14.2)
        .L(3.2, 14.1)
        .C(4.2, 14.1, 4.2, 15.3, 3.2, 15.35)
        .L(-0.6, 15.45)
        .C(-1.6, 15.5, -1.6, 16.6, -0.6, 16.65)
        .L(3.2, 16.55)
        .C(4.2, 16.55, 4.2, 17.7, 3.2, 17.75)
        .L(-0.6, 17.85)
        .C(-1.6, 17.9, -1.6, 19.0, -0.6, 19.05)
        .L(3.4, 18.95), 0.62);
    // 環鏈一（統領雷神——弧上五環）
    const 鏈 = (起, 環, 終, 寬 = 0.55) => bi.一筆({ 寬: 寬 * u, 起: '藏', 收: '出' }, p => {
        p.M(起[0], 起[1]);
        for (const [ex, ez] of 環) {
            p.C(ex + 0.8, ez - 0.6, ex - 0.85, ez - 0.75, ex - 0.65, ez + 0.15);
            p.C(ex - 0.45, ez + 0.7, ex + 0.6, ez + 0.55, ex + 0.4, ez - 0.2);
        }
        p.C(終[0] + 0.8, 終[1] - 0.6, 終[0] + 0.4, 終[1] - 0.2, 終[0], 終[1]);
    });
    鏈([-9.4, 17.6], [[-8.2, 16.9], [-6.9, 16.5], [-5.6, 16.4], [-4.4, 16.6]], [-3.2, 17.4]);
    // 環鏈二（水帝龍精——短鏈揚尾）
    鏈([-11.2, 12.9], [[-10.2, 12.3], [-9.1, 12.0], [-8.0, 12.0]], [-6.9, 11.4]);
    // 環鏈三（急速馳奔——下彎四環）
    鏈([-6.4, 23.2], [[-5.3, 23.9], [-4.1, 24.2], [-2.9, 24.1]], [-1.8, 23.3]);
    // 天德鉤（乙形長曳）・月德鉤（小2形）
    線(p => p.M(0.6, 21.8)
        .C(1.8, 21.4, 3.0, 21.5, 3.4, 22.2)
        .C(3.7, 22.8, 3.2, 23.4, 2.4, 23.5)
        .C(3.2, 23.9, 3.8, 24.5, 3.6, 25.2)
        .C(3.4, 25.8, 2.6, 26.0, 1.8, 25.7), 0.8);
    線(p => p.M(4.8, 23.6)
        .C(5.6, 23.4, 6.2, 23.7, 6.2, 24.3)
        .C(6.2, 24.9, 5.6, 25.2, 5.0, 25.1), 0.7);
    // 星陣（雷公江赫衝雷——四曜方陣＋珠鏈自右上升）
    const 圈 = (x, z, r = 0.4) => {
        const c = bi.ctx;
        c.save();
        c.lineWidth = 0.3 * u;
        bi.A(x, z, r);
        c.restore();
    };
    const 星線 = (a, b) => {
        const dx = b[0] - a[0], dz = b[1] - a[1], L = Math.hypot(dx, dz), t0 = 0.45 / L;
        線(p => p.M(a[0] + dx * t0, a[1] + dz * t0).L(b[0] - dx * t0, b[1] - dz * t0), 0.42);
    };
    const A = [-10.6, 19.4], B = [-7.0, 18.8], C0 = [-10.2, 22.9], D = [-6.5, 22.3];
    星線(A, B);
    星線(A, C0);
    星線(C0, D);
    星線(B, D);
    for (const s of [A, B, C0, D])
        圈(s[0], s[1], 0.44);
    // 珠鏈（四小圈自 B 上升）
    let bx = -6.7, bz = 18.0;
    for (let i = 0; i < 4; i++) {
        圈(bx, bz, 0.24);
        if (i < 3)
            線(p => p.M(bx + 0.06, bz - 0.26).L(bx + 0.18, bz - 0.78), 0.32);
        bx += 0.22;
        bz -= 1.04;
    }
};
